//         {activeTab === 'inventory' && ( <div className="max-w-7xl mx-auto animate-fade-in"><h2 className="text-3xl font-serif mb-8 text-stone-900">Inventory Engine</h2><div className="grid grid-cols-1 xl:grid-cols-3 gap-8"><div className="space-y-6 xl:col-span-1"><div className={\`glass-panel p-6 rounded-2xl transition-all \${editingId ? 'ring-2 ring-amber-500 shadow-amber-500/20 shadow-xl' : ''}\`}><div className="flex justify-between items-center mb-6 border-b pb-2"><h3 className="text-sm font-bold uppercase tracking-widest">{editingId ? 'Edit Design' : 'Add Design'}</h3>{editingId && <button type="button" onClick={cancelEdit} className="text-xs text-stone-500 underline">Cancel</button>}</div><form onSubmit={handleSubmit} className="space-y-4"><div><label className="block text-[10px] font-bold uppercase tracking-widest text-stone-500 mb-1">Name</label><input type="text" name="name" required value={formData.name} onChange={handleChange} className="w-full p-3 border rounded-xl outline-none focus:border-amber-600 text-sm" /></div><div><label className="block text-[10px] font-bold uppercase tracking-widest text-stone-500 mb-1">Category</label><select name="category" required value={formData.category} onChange={handleChange} className="w-full p-3 border rounded-xl outline-none focus:border-amber-600 text-sm bg-white"><option value="" disabled>Select</option>{categories.map(c => <option key={c._id} value={c.name}>{c.name}</option>)}</select></div><div className="grid grid-cols-2 gap-4"><div><label className="block text-[10px] font-bold uppercase tracking-widest text-stone-500 mb-1">Price</label><input type="number" name="price" required value={formData.price} onChange={handleChange} className="w-full p-3 border rounded-xl outline-none focus:border-amber-600 text-sm" /></div><div><label className="block text-[10px] font-bold uppercase tracking-widest text-stone-500 mb-1">Stock</label><input type="number" name="stock" required value={formData.stock} onChange={handleChange} className="w-full p-3 border rounded-xl outline-none focus:border-amber-600 text-sm" /></div></div><div className="p-4 bg-stone-50 border border-dashed rounded-xl"><label className="block text-[10px] font-bold uppercase tracking-widest text-stone-500 mb-2">Image</label><input type="file" accept="image/*" ref={fileInputRef} onChange={(e) => setImageFile(e.target.files[0])} className="text-xs w-full file:mr-4 file:py-2 file:px-4 file:rounded-lg file:border-0 file:text-xs file:font-bold file:bg-stone-200 file:text-stone-700 cursor-pointer" /><p className="text-[10px] text-stone-400 mt-3 text-center uppercase tracking-widest">OR</p><input type="url" name="imageUrl" value={formData.imageUrl} onChange={handleChange} className="mt-3 w-full p-2 border rounded-lg text-xs outline-none focus:border-amber-600" placeholder="Paste URL" />{formData.imageUrl && !imageFile && <div className="mt-3 h-20 w-20 relative mx-auto border rounded-xl overflow-hidden shadow-sm"><img src={formData.imageUrl} className="h-full w-full object-cover" /></div>}</div><button type="submit" className="w-full text-white p-4 rounded-xl bg-stone-900 hover:bg-stone-800 transition font-bold uppercase tracking-widest text-xs mt-6">{editingId ? 'Update Design' : 'Save Design'}</button></form></div></div><div className="glass-panel p-0 rounded-2xl xl:col-span-2 h-fit overflow-hidden"><div className="p-6 border-b bg-white/50"><h3 className="text-sm font-bold text-stone-800 uppercase tracking-widest">Master Table</h3></div><div className="overflow-x-auto"><table className="w-full text-left divide-y divide-stone-200"><thead><tr className="bg-stone-50/50 text-[10px] uppercase text-stone-400 font-bold tracking-widest"><th className="p-4">Product</th><th className="p-4">Price</th><th className="p-4">Status</th><th className="p-4 text-right">Actions</th></tr></thead><tbody className="divide-y divide-stone-100 bg-white/30">{inventory.map((item) => (<tr key={item._id} className="hover:bg-white/80 transition"><td className="p-4 flex gap-4 items-center"><img src={item.imageUrl} className="h-14 w-14 rounded-xl object-cover shadow-sm" /><div><p className="font-bold text-stone-900 text-sm">{item.name}</p><p className="text-[10px] uppercase tracking-widest font-bold mt-1 text-stone-400">{item.stock} left</p></div></td><td className="p-4 text-sm font-bold text-stone-700">₹{(item.price || 0).toLocaleString('en-IN')}</td><td className="p-4"><span className={\`text-[9px] uppercase tracking-widest font-bold px-2 py-1 rounded-md \${item.isPublished ? 'bg-green-100 text-green-700' : 'bg-stone-200 text-stone-500'}\`}>{item.isPublished ? 'Live' : 'Draft'}</span></td><td className="p-4 text-right space-x-2"><button onClick={() => handleEditClick(item)} className="text-blue-500 hover:bg-blue-50 p-2 rounded-lg transition"><Edit size={16}/></button><button onClick={() => handleDeleteProduct(item._id)} className="text-red-500 hover:bg-red-50 p-2 rounded-lg transition"><Trash2 size={16}/></button></td></tr>))}</tbody></table></div></div></div></div> )}
//         {activeTab === 'taxonomy' && ( <div className="max-w-4xl mx-auto animate-fade-in"><h2 className="text-3xl font-serif mb-8 text-stone-900">Taxonomy & Collections</h2><div className="glass-panel p-8 rounded-2xl"><h3 className="text-sm font-bold uppercase tracking-widest mb-6 border-b pb-4 flex items-center gap-2"><ListTree size={16}/> Manage Categories</h3><form onSubmit={handleAddCategory} className="flex gap-4 mb-8"><input type="text" value={newCategory} onChange={(e) => setNewCategory(e.target.value)} className="flex-1 p-4 border rounded-xl text-sm outline-none focus:border-amber-600 bg-stone-50/50" placeholder="e.g. Summer Bridal Collection" /><button type="submit" className="bg-stone-900 text-white px-8 py-4 rounded-xl text-xs font-bold uppercase tracking-widest hover:bg-stone-800 transition">Create Collection</button></form><div className="grid grid-cols-1 md:grid-cols-2 gap-4">{categories.map(c => (<div key={c._id} className="bg-white border border-stone-200 p-4 rounded-xl flex justify-between items-center shadow-sm"><span className="font-bold text-stone-800">{c.name}</span><button onClick={() => handleDeleteCategory(c._id)} className="text-stone-400 hover:text-red-500 hover:bg-red-50 p-2 rounded-lg transition"><Trash2 size={16}/></button></div>))}</div></div></div> )}
//         {activeTab === 'marketing' && ( <div className="max-w-7xl mx-auto animate-fade-in"><h2 className="text-3xl font-serif mb-8 text-stone-900">Marketing & Conversions</h2><div className="grid grid-cols-1 md:grid-cols-2 gap-8"><div className="glass-panel p-8 rounded-2xl h-fit sticky top-10"><h3 className="text-sm font-bold uppercase tracking-widest mb-6 border-b pb-4 flex items-center gap-2"><Tag size={16}/> Advanced Discount Rules</h3><form onSubmit={handleAddPromo} className="space-y-6"><div><label className="block text-[10px] font-bold uppercase tracking-widest text-stone-500 mb-2">Campaign Code</label><input type="text" required value={newPromo.code} onChange={(e) => setNewPromo({...newPromo, code: e.target.value.toUpperCase()})} placeholder="e.g. DIWALI20" className="w-full p-4 border rounded-xl outline-none focus:border-amber-600 text-sm uppercase font-mono tracking-widest font-bold bg-stone-50/50" /></div><div className="grid grid-cols-2 gap-4"><div><label className="block text-[10px] font-bold uppercase tracking-widest text-stone-500 mb-2">Discount (%)</label><input type="number" min="1" max="100" required value={newPromo.discountPercentage} onChange={(e) => setNewPromo({...newPromo, discountPercentage: e.target.value})} placeholder="20" className="w-full p-4 border rounded-xl outline-none focus:border-amber-600 text-sm bg-stone-50/50" /></div><div><label className="block text-[10px] font-bold uppercase tracking-widest text-stone-500 mb-2">Min. Order (₹)</label><input type="number" required value={newPromo.minOrderValue} onChange={(e) => setNewPromo({...newPromo, minOrderValue: e.target.value})} placeholder="5000" className="w-full p-4 border rounded-xl outline-none focus:border-amber-600 text-sm bg-stone-50/50" /></div></div><button type="submit" className="w-full text-white p-4 rounded-xl bg-stone-900 hover:bg-stone-800 transition font-bold uppercase tracking-widest text-xs shadow-lg shadow-stone-900/20 mt-4">Activate Campaign</button></form></div><div className="glass-panel p-8 rounded-2xl"><h3 className="text-sm font-bold uppercase tracking-widest mb-6 border-b pb-4">Active Campaigns</h3><div className="space-y-4">{promos.length === 0 ? (<p className="text-stone-400 text-sm italic">No active promotions.</p>) : (promos.map(promo => (<div key={promo._id} className="bg-white p-6 rounded-xl border shadow-sm flex justify-between items-center group"><div><p className="font-mono font-bold tracking-widest text-lg text-amber-700">{promo.code}</p><div className="flex items-center gap-3 mt-1"><span className="text-xs text-stone-500 uppercase tracking-widest font-bold">{promo.discountPercentage}% OFF</span><span className="text-[10px] text-stone-400 bg-stone-100 px-2 py-0.5 rounded uppercase tracking-widest">Min ₹{(promo.minOrderValue || 0).toLocaleString('en-IN')}</span></div></div><button onClick={() => handleDeletePromo(promo._id)} className="text-stone-300 hover:text-white hover:bg-red-500 p-2 rounded-lg transition border border-transparent hover:border-red-600"><Trash2 size={16}/></button></div>)))}</div></div></div></div> )}
